func incrementConsecutiveLadderExhaustions(args ...any) error {
	ctx := context.Background()
	var store ExecuteBeadLoopStore
	var beadID string
	for _, arg := range args {
		switch v := arg.(type) {
		case context.Context:
			if v != nil {
