			}
		case ExecuteBeadLoopStore:
			store = v
		case string:
			if beadID == "" {
				beadID = v
			}
		}
	}
	if store == nil {
		return fmt.Errorf("incrementConsecutiveLadderExhaustions: store required")
	}
	if beadID == "" {
		return fmt.Errorf("incrementConsecutiveLadderExhaustions: bead id required")
