package workerstatus

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// newSystemScanner returns a /proc-based scanner.
func newSystemScanner() Scanner {
	return &procScanner{now: time.Now}
}

// procScanner enumerates live `ddx work` and `ddx try` processes by reading
// /proc on Linux. Each candidate's command line, cwd, and start time are
// pulled directly from the kernel, so the scan does not depend on any DDx
// server state.
type procScanner struct {
	now func() time.Time
}

func (s *procScanner) Scan(ctx context.Context) ([]LiveWorker, error) {
	entries, err := os.ReadDir("/proc")
	if err != nil {
		return nil, fmt.Errorf("read /proc: %w", err)
	}

	workers := make([]LiveWorker, 0)
	bootTime := readBootTime("/proc/stat")
	for _, e := range entries {
		if ctx != nil && ctx.Err() != nil {
			return nil, ctx.Err()
		}
		if !e.IsDir() {
			continue
		}
		pid, err := strconv.Atoi(e.Name())
		if err != nil || pid <= 0 {
			continue
		}
		w, ok := s.inspect(pid, bootTime)
		if !ok {
			continue
		}
		workers = append(workers, w)
	}
	return workers, nil
}

func (s *procScanner) inspect(pid int, bootTime time.Time) (LiveWorker, bool) {
	base := filepath.Join("/proc", strconv.Itoa(pid))
	cmdlineRaw, err := os.ReadFile(filepath.Join(base, "cmdline"))
	if err != nil {
		return LiveWorker{}, false
	}
	cmdline := decodeCmdline(cmdlineRaw)
	if !looksLikeDDxWorker(cmdline) {
		return LiveWorker{}, false
	}

	cwd, _ := os.Readlink(filepath.Join(base, "cwd"))

	projectRoot := resolveWorkerProjectRoot(cmdline, cwd)
	beadID, worktree := InferBead(cmdline, cwd)

	started := time.Time{}
	if !bootTime.IsZero() {
		if startClk, ok := readStartTimeClockTicks(filepath.Join(base, "stat")); ok {
			ticks := clockTicksPerSecond()
			seconds := float64(startClk) / ticks
			started = bootTime.Add(time.Duration(seconds * float64(time.Second)))
		}
	}
	now := s.now().UTC()
	if started.IsZero() {
		started = now
	}
	age := now.Sub(started)
	if age < 0 {
		age = 0
	}

	return LiveWorker{
		PID:               pid,
		Command:           cmdline,
		StartedAt:         started.UTC(),
		AgeSeconds:        age.Seconds(),
		Age:               FormatAge(age),
		ProjectRoot:       projectRoot,
		BeadID:            beadID,
		ExecutionWorktree: worktree,
		Cwd:               cwd,
	}, true
}

// decodeCmdline converts /proc/<pid>/cmdline's NUL-separated args into a
// space-separated string suitable for display and substring matching.
func decodeCmdline(raw []byte) string {
	if len(raw) == 0 {
		return ""
	}
	if raw[len(raw)-1] == 0 {
		raw = raw[:len(raw)-1]
	}
	parts := bytes.Split(raw, []byte{0})
	out := make([]string, 0, len(parts))
	for _, p := range parts {
		if len(p) == 0 {
			continue
		}
		out = append(out, string(p))
	}
	return strings.Join(out, " ")
}

// looksLikeDDxWorker reports whether the argv resembles a `ddx work` or
// `ddx try` invocation. We match against argv[0]'s basename so a binary
// installed at any path (or via `go run ./cli ...`) is still detected.
func looksLikeDDxWorker(cmdline string) bool {
	if cmdline == "" {
		return false
	}
	parts := strings.Fields(cmdline)
	if len(parts) < 2 {
		return false
	}
	bin := filepath.Base(parts[0])
	if bin != "ddx" {
		// Allow `go run ... ddx work` style invocations where the binary
		// path ends in `cmd` or similar but the args still start with the
		// ddx subcommand. We only consider real ddx binaries here.
		return false
	}
	sub := parts[1]
	if sub == "try" {
		return true
	}
	if sub != "work" {
		return false
	}
	if len(parts) >= 3 && isWorkHelperSubcommand(parts[2]) {
		return false
	}
	return true
}

func isWorkHelperSubcommand(arg string) bool {
	switch arg {
	case "analyze", "clear-cooldowns", "focus", "metrics", "plan", "status":
		return true
	default:
		return false
	}
}

// resolveWorkerProjectRoot derives the project root the worker is operating
// on. The order of preference matches how `ddx work` itself resolves --project
// (CLI flag → DDX_PROJECT_ROOT env → cwd's git root). When the cwd points at
// an isolated execute-bead worktree (a sibling of the real checkout), we
// fall back to the surrounding git root rather than the worktree path.
func resolveWorkerProjectRoot(cmdline, cwd string) string {
	if flagVal := parseFlagValue(cmdline, "--project"); flagVal != "" {
		return canonicalPath(flagVal)
	}
	if cwd == "" {
		return ""
	}
	// If cwd is inside an isolated execute-bead worktree the git root will
	// be the worktree itself; that is a per-attempt artefact, not the
	// originating project. Worktree paths conventionally live under either
	// `<project>/.ddx/.execute-bead-wt-*` or under DDX_EXEC_WT_DIR. Caller
	// resolution here only needs to keep workers consistent: we always
	// derive ProjectRoot from cwd's git root via the same helper the worker
	// itself would use.
	root := gitpkg.FindProjectRoot(cwd)
	return canonicalPath(root)
}

// parseFlagValue returns the argument value for a `--flag <value>` or
// `--flag=<value>` form embedded in a space-separated command line. The
// match is anchored at word boundaries so `--projectile` does not satisfy
// `--project`.
func parseFlagValue(cmdline, flag string) string {
	parts := strings.Fields(cmdline)
	for i, p := range parts {
		if p == flag && i+1 < len(parts) {
			return parts[i+1]
		}
		if strings.HasPrefix(p, flag+"=") {
			return strings.TrimPrefix(p, flag+"=")
		}
	}
	return ""
}

func readBootTime(statPath string) time.Time {
	data, err := os.ReadFile(statPath)
	if err != nil {
		return time.Time{}
	}
	for _, line := range strings.Split(string(data), "\n") {
		if !strings.HasPrefix(line, "btime ") {
			continue
		}
		fields := strings.Fields(line)
		if len(fields) < 2 {
			continue
		}
		sec, err := strconv.ParseInt(fields[1], 10, 64)
		if err != nil {
			return time.Time{}

package agent

// provider_failure.go defines the typed provider-failure taxonomy at the
// DDx/Fizeau boundary (ddx-3b721804). A provider failure is any pre-dispatch
// Execute error or failed final event whose root cause is provider/model
// availability, credentials, quota/rate limiting, endpoint reachability, or
// harness/configuration validity — as opposed to a model giving up on the task.
//
// DDx is the abstraction that lets unattended workers continue through provider
// variance across machines. A generic, untyped provider failure that names no
// cause, no fallback action, and no route-health evidence is a product bug, so
// this file gives every such failure a typed reason, a retryability verdict, a
// fallback decision, and durable evidence.
//
// Routing itself stays in Fizeau (aliases, model discovery, provider catalog);
// DDx only classifies the outcome and decides whether an unpinned worker should
// fall back to another eligible route or a pinned worker should fail loudly.

import (
	"errors"
	"strings"

	agentlib "github.com/easel/fizeau"
)

// Provider-failure taxonomy. provider_connectivity and no_viable_provider reuse
// the existing FailureMode* constants (execute_bead_status.go) so the rest of
// the loop's route-health handling continues to recognize them.
const (
	FailureModeProviderAuth               = "provider_auth"
	FailureModeProviderRateLimit          = "provider_rate_limit"
	FailureModeProviderQuota              = "provider_quota"
	FailureModeProviderModelUnavailable   = "provider_model_unavailable"
	FailureModeProviderHarnessUnavailable = "provider_harness_unavailable"
	FailureModeProviderConfigInvalid      = "provider_config_invalid"
	FailureModeUnknownProviderFailure     = "unknown_provider_failure"
)

// ProviderFailure is the typed classification of a provider/route failure.
type ProviderFailure struct {
	// Reason is one of the taxonomy constants above (or the reused
	// FailureModeProviderConnectivity / FailureModeNoViableProvider).
	Reason string
	// Retryable reports whether a *different* eligible route could succeed.
	// True for transient/availability failures an unpinned worker should fall
	// back from; false for whole-fleet conditions (no viable provider) or
	// configuration bugs that another route cannot fix.
	Retryable bool
	// Disruption is the disruption_reason stamped on the report. A provider
	// failure is always a worker-side disruption (the model never got to give
	// up), so it mirrors Reason.
	Disruption string
}

// ProviderFailureError wraps a pre-dispatch Execute error with its typed
// classification so callers can recover the taxonomy via errors.As without
// re-parsing free text. The wrapped error's message is preserved verbatim.
type ProviderFailureError struct {
	Failure ProviderFailure
	Err     error
}

func (e *ProviderFailureError) Error() string {
	if e == nil || e.Err == nil {
		return ""
	}
	return e.Err.Error()
}

func (e *ProviderFailureError) Unwrap() error {
	if e == nil {
		return nil
	}
	return e.Err
}

// ClassifyProviderFailure normalizes a free-text provider/route error into the
// typed taxonomy. It returns ok=false when the text does not name a recognized
// provider/route/config cause, so callers can leave non-provider failures
// (test_failure, merge_conflict, ...) classified by ClassifyFailureMode.
//
// The order is significant: config-invalid and auth/quota/rate-limit markers
// are checked before the broad connectivity bucket so a "429" or "unauthorized"
// is not swallowed as a generic timeout.
func ClassifyProviderFailure(errMsg string) (ProviderFailure, bool) {
	lower := strings.ToLower(strings.TrimSpace(errMsg))
	if lower == "" {
		return ProviderFailure{}, false
	}
	switch {
	case containsAny(lower,
		"passthrough constraint unsatisfiable",
		"passthrough constraint:",
		"invalid configuration",
		"config invalid",
		"invalid endpoint",
		"misconfigured",
		"unknown provider",
		"harness model incompatible",
		"model incompatible with",
		"incompatible with power bounds"):
		return providerFailure(FailureModeProviderConfigInvalid, false), true
	case containsAny(lower,
		"unauthorized",
		"401",
		"invalid api key",
		"invalid_api_key",
		"authentication failed",
		"authentication_error",
		"no api key",
		"missing api key",
		"forbidden",
		"403"):
		return providerFailure(FailureModeProviderAuth, true), true
	case containsAny(lower,
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"out of quota",
		"quota"):
		return providerFailure(FailureModeProviderQuota, true), true
	case containsAny(lower,
		"rate limit",
		"rate_limit",
		"ratelimit",
		"too many requests",
		"429"):
		return providerFailure(FailureModeProviderRateLimit, true), true
	case containsAny(lower, "is not routable", "not routable", "model_not_found"),
		strings.Contains(lower, "model") && containsAny(lower,
			"not available",
			"unavailable",
			"not found",
			"no such",
			"unknown",
			"incompatible"):
		return providerFailure(FailureModeProviderModelUnavailable, true), true
	case containsAny(lower,
		"harness unavailable",
		"harness not available",
		"harness not installed",
		"unknown harness",
		"no harness configured",
		"executable file not found",
		"command not found"):
		return providerFailure(FailureModeProviderHarnessUnavailable, true), true
	case containsAny(lower,
		"no viable provider",
		"no viable harness",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint"):
		return providerFailure(FailureModeNoViableProvider, false), true
	case containsAny(lower,
		"connection refused",
		"connection reset",
		"no route to host",
		"network is unreachable",
		"no such host",
		"i/o timeout",
		"dial tcp",
		"provider_connectivity",
		"provider request timeout",
		"provider timeout",
		"endpoint timeout",
		"bad gateway",
		"service unavailable",
		"gateway timeout",
		"502", "503", "504"):
		return providerFailure(FailureModeProviderConnectivity, true), true
	}
	return ProviderFailure{}, false
}

// ClassifyServiceExecuteError classifies a pre-dispatch FizeauService.Execute
// error. Because a pre-dispatch failure means routing never produced a viable
// dispatch, every such error is a provider-boundary failure: when no specific
// marker matches it falls back to unknown_provider_failure (non-retryable) so
// the outcome is always typed rather than generic execution_failed.
func ClassifyServiceExecuteError(err error) ProviderFailure {
	if err == nil {
		return providerFailure(FailureModeUnknownProviderFailure, false)
	}
	var modelErr *agentlib.ErrHarnessModelIncompatible
	if errors.As(err, &modelErr) {
		return providerFailure(FailureModeProviderModelUnavailable, true)
	}
	if pf, ok := ClassifyProviderFailure(err.Error()); ok {
		return pf
	}
	return providerFailure(FailureModeUnknownProviderFailure, false)
}

// ApplyProviderFailureToReport stamps a typed provider failure onto a report:
// the typed reason as outcome_reason and the worker-disruption markers so the
// retry/fallback layer treats it as route-health evidence, not a model give-up.
func ApplyProviderFailureToReport(report *ExecuteBeadReport, pf ProviderFailure) {
	if report == nil || pf.Reason == "" {
		return
	}
	report.OutcomeReason = pf.Reason
	report.Disrupted = true
	report.DisruptionReason = pf.Disruption
}

// IsProviderFailureReason reports whether reason is one of the typed
// provider-failure taxonomy values (including the reused connectivity /
// no-viable-provider reasons).
func IsProviderFailureReason(reason string) bool {
	switch strings.TrimSpace(reason) {
	case FailureModeProviderAuth,
		FailureModeProviderRateLimit,
		FailureModeProviderQuota,
		FailureModeProviderModelUnavailable,
		FailureModeProviderHarnessUnavailable,
		FailureModeProviderConfigInvalid,
		FailureModeUnknownProviderFailure,
		FailureModeProviderConnectivity,
		FailureModeNoViableProvider:
		return true

		return true
	default:
		return false
	}
}

// ProviderPin captures an operator's explicit routing pins. A pinned worker
// must never have its pin silently widened: a typed provider failure on a
// pinned route is reported as hard-pin-exhausted with operator remediation.
type ProviderPin struct {
	Harness  string
	Provider string
	Model    string
}

// Any reports whether the operator pinned any routing dimension.
func (p ProviderPin) Any() bool {
	return strings.TrimSpace(p.Harness) != "" ||
		strings.TrimSpace(p.Provider) != "" ||
		strings.TrimSpace(p.Model) != ""
}

func (p ProviderPin) describe() string {
	var parts []string
	if h := strings.TrimSpace(p.Harness); h != "" {
		parts = append(parts, "--harness "+h)
	}
	if pr := strings.TrimSpace(p.Provider); pr != "" {
		parts = append(parts, "--provider "+pr)
	}
	if m := strings.TrimSpace(p.Model); m != "" {
		parts = append(parts, "--model "+m)
	}
	return strings.Join(parts, " ")
}

// FallbackDecision records whether the worker should attempt another route and,
// when it should not, why fallback stopped. The StopReason feeds durable
// evidence (fallback_stop_reason).
type FallbackDecision struct {
	Continue   bool
	StopReason string
}

// Fallback stop reasons used in evidence.
const (
	FallbackStopHardPinExhausted = "hard_pin_exhausted"
)

// DecideProviderFallback decides what an worker does after a typed provider
// failure. A pinned worker never widens its pin, so any provider failure stops
// with hard_pin_exhausted. An unpinned worker continues when the failure is
// retryable (a different eligible route may succeed) and otherwise stops naming
// the typed reason (e.g. no_viable_provider — nothing left to try).
func DecideProviderFallback(pf ProviderFailure, pinned bool) FallbackDecision {
	if pinned {
		return FallbackDecision{Continue: false, StopReason: FallbackStopHardPinExhausted}
	}
	if pf.Retryable {
		return FallbackDecision{Continue: true}
	}
	return FallbackDecision{Continue: false, StopReason: pf.Reason}
}

// ProviderFailureEvidence is the durable record persisted on the bead/run when
// a provider failure occurs. It proves what was requested, what (if anything)
// resolved, the typed failure, its retryability, whether fallback was
// attempted, and why fallback stopped — so an operator reading the bead can see
// the full route-health decision without re-running the worker.
type ProviderFailureEvidence struct {
	RequestedHarness   string `json:"requested_harness,omitempty"`
	RequestedProvider  string `json:"requested_provider,omitempty"`
	RequestedModel     string `json:"requested_model,omitempty"`
	RequestedProfile   string `json:"requested_profile,omitempty"`
	RequestedMinPower  int    `json:"requested_min_power,omitempty"`
	RequestedMaxPower  int    `json:"requested_max_power,omitempty"`
	ResolvedHarness    string `json:"resolved_harness,omitempty"`
	ResolvedProvider   string `json:"resolved_provider,omitempty"`
	ResolvedModel      string `json:"resolved_model,omitempty"`
	TypedFailure       string `json:"typed_failure"`
	Retryable          bool   `json:"retryable"`
	FallbackAttempted  bool   `json:"fallback_attempted"`
	FallbackStopReason string `json:"fallback_stop_reason,omitempty"`
}

// ProviderFailureRequest captures the constraints the worker requested for the
// failed dispatch.
type ProviderFailureRequest struct {
	Harness  string
	Provider string
	Model    string
	Profile  string
	MinPower int
	MaxPower int
}

// ResolvedRoute captures the route Fizeau resolved, when any route resolved
// before the failure. Nil/zero means routing never produced a candidate.
type ResolvedRoute struct {
	Harness  string
	Provider string
	Model    string
}

// BuildProviderFailureEvidence assembles the durable evidence for a provider
// failure from the requested constraints, the resolved route (if any), the
// typed failure, and the fallback decision.
func BuildProviderFailureEvidence(req ProviderFailureRequest, resolved *ResolvedRoute, pf ProviderFailure, decision FallbackDecision) ProviderFailureEvidence {
	ev := ProviderFailureEvidence{
		RequestedHarness:   req.Harness,
		RequestedProvider:  req.Provider,
		RequestedModel:     req.Model,
		RequestedProfile:   req.Profile,
		RequestedMinPower:  req.MinPower,
		RequestedMaxPower:  req.MaxPower,
		TypedFailure:       pf.Reason,
		Retryable:          pf.Retryable,
		FallbackAttempted:  decision.Continue,
		FallbackStopReason: decision.StopReason,
	}
	if resolved != nil {
		ev.ResolvedHarness = resolved.Harness
		ev.ResolvedProvider = resolved.Provider
		ev.ResolvedModel = resolved.Model
	}
	return ev
}

// MarkHardPinExhausted refines a report for a pinned worker whose pinned route
// hit a typed provider failure. It preserves the pin (it never clears the pin
// or widens routing), records the typed failure as the outcome reason, and
// writes operator remediation naming the exact pin so the operator can act.
func MarkHardPinExhausted(report *ExecuteBeadReport, pin ProviderPin, pf ProviderFailure) {
	if report == nil || pf.Reason == "" {
		return
	}
	report.OutcomeReason = pf.Reason
	report.Disrupted = true
	report.DisruptionReason = pf.Disruption
	remediation := "hard pin exhausted: typed provider failure " + pf.Reason +
		" on pinned route (" + pin.describe() + "); the pin was not widened. " +
		"Remediation: fix the pinned provider/model/harness, or rerun without the pin to let DDx fall back to another eligible route."
	if strings.TrimSpace(report.Detail) == "" {
		report.Detail = remediation
	} else {
		report.Detail = report.Detail + "; " + remediation
	}
}

func providerFailure(reason string, retryable bool) ProviderFailure {
	return ProviderFailure{Reason: reason, Retryable: retryable, Disruption: reason}
}

package agent

import "testing"

// TestFailureModeClassifyWorker exercises ClassifyFailureMode against the
// known worker-level signals. The acceptance contract enumerates the full
// set of modes: context_overflow, merge_conflict, test_failure,
// build_failure, timeout, auth_error, no_changes, unknown (plus "" on
// success). Each case names its input so a pattern drift is easy to spot
// in test failures.
func TestFailureModeClassifyWorker(t *testing.T) {
	cases := []struct {
		name     string
		outcome  string
		exitCode int
		errMsg   string
		want     string
	}{
		{"success_clean", ExecuteBeadOutcomeTaskSucceeded, 0, "", ""},
		{"no_changes", ExecuteBeadOutcomeTaskNoChanges, 0, "", FailureModeNoChanges},
		{"no_evidence", ExecuteBeadOutcomeTaskNoEvidence, 0, "", FailureModeNoEvidenceProduced},
		{"no_changes_ignores_error_text", ExecuteBeadOutcomeTaskNoChanges, 0, "build failed", FailureModeNoChanges},

		// Context / long-context hangs.
		{"context_length_exceeded", ExecuteBeadOutcomeTaskFailed, 1,
			"context_length_exceeded: prompt exceeds 200000 tokens", FailureModeContextOverflow},
		{"prompt_too_long", ExecuteBeadOutcomeTaskFailed, 1,
			"Error: prompt is too long for model", FailureModeContextOverflow},
		{"maximum_context", ExecuteBeadOutcomeTaskFailed, 1,
			"request exceeds the maximum context length", FailureModeContextOverflow},

		// Auth / quota.
		{"unauthorized_401", ExecuteBeadOutcomeTaskFailed, 1,
			"401 Unauthorized: invalid API key", FailureModeAuthError},
		{"insufficient_quota", ExecuteBeadOutcomeTaskFailed, 1,
			"insufficient_quota: you have exceeded your current quota", FailureModeAuthError},
		{"rate_limit", ExecuteBeadOutcomeTaskFailed, 1,
			"429 Too Many Requests: rate limit reached", FailureModeAuthError},

		// Timeout.
		{"context_deadline_exceeded", ExecuteBeadOutcomeTaskFailed, 1,
			"context deadline exceeded", FailureModeTimeout},
		{"timed_out", ExecuteBeadOutcomeTaskFailed, 1,
			"agent call timed out after 2h", FailureModeTimeout},

		// Worktree loss: infrastructure lost the isolated attempt checkout
		// before DDx could inspect the result commit.
		{"worktree_lost_chdir", ExecuteBeadOutcomeTaskFailed, 1,
			"failed to read worktree HEAD: git rev-parse HEAD: chdir /tmp/ddx-exec-wt/.execute-bead-wt-ddx-test-attempt: no such file or directory", FailureModeWorktreeLost},

		// Merge conflict (worker-visible when orchestrator surfaces it via
		// Reason/Error). The landing classifier refines this; the worker
		// classifier recognises the text so a pre-landing result is still
		// tagged correctly.
		{"merge_conflict", ExecuteBeadOutcomeTaskFailed, 1,
			"merge conflict in cli/cmd/agent_metrics.go", FailureModeMergeConflict},

		// Build failure: shipped code that does not compile.
		{"go_compile_error", ExecuteBeadOutcomeTaskFailed, 1,
			"undefined: foo.Bar", FailureModeBuildFailure},
		{"build_failed", ExecuteBeadOutcomeTaskFailed, 1,
			"build failed with 3 errors", FailureModeBuildFailure},

		// Test failure.
		{"go_test_fail_marker", ExecuteBeadOutcomeTaskFailed, 1,
			"--- FAIL: TestX (0.01s)", FailureModeTestFailure},
		{"tests_failed", ExecuteBeadOutcomeTaskFailed, 1,
			"tests failed: 3 of 12 assertions did not pass", FailureModeTestFailure},

		// Unknown fallback: non-zero exit with no recognised pattern.
		{"unknown_error", ExecuteBeadOutcomeTaskFailed, 1,
			"something exploded", FailureModeUnknown},
		{"no_error_text_non_zero", ExecuteBeadOutcomeTaskFailed, 137, "",
			FailureModeUnknown},
		{"resolveroute_zero_exit_error", ExecuteBeadOutcomeTaskFailed, 0,
			"ResolveRoute: no viable routing candidate: 3 candidates rejected", FailureModeNoViableProvider},

		// Ordering: timeout wins over test/build keywords when both appear.
		{"timeout_beats_test_failure", ExecuteBeadOutcomeTaskFailed, 1,
			"test timed out after 5m", FailureModeTimeout},
		// Ordering: auth wins over generic keywords.
		{"auth_beats_build", ExecuteBeadOutcomeTaskFailed, 1,
			"401 unauthorized: build failed", FailureModeAuthError},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := ClassifyFailureMode(tc.outcome, tc.exitCode, tc.errMsg)
			if got != tc.want {
				t.Fatalf("ClassifyFailureMode(%q, %d, %q) = %q, want %q",
					tc.outcome, tc.exitCode, tc.errMsg, got, tc.want)
			}
		})
	}
}

func TestFailureModeClassifyWorker_WorktreeLost(t *testing.T) {
	errText := "failed to read worktree HEAD: git rev-parse HEAD: chdir /tmp/ddx-exec-wt/.execute-bead-wt-ddx-test-attempt: no such file or directory"
	got := ClassifyFailureMode(ExecuteBeadOutcomeTaskFailed, 1, errText)
	if got != FailureModeWorktreeLost {
		t.Fatalf("ClassifyFailureMode worktree loss = %q, want %q", got, FailureModeWorktreeLost)
	}
}

// TestFailureModeLandingRefines exercises classifyLandingFailureMode, which
// is how ApplyLandingToResult folds landing-level signals (merge conflict,
// gate failure) into the final failure_mode. A clean merge clears the
// worker's mode; merge conflict and gate failure override it; other
// preserved reasons defer to the worker's classification.
func TestFailureModeLandingRefines(t *testing.T) {
	gateFailTest := []GateCheckResult{{
		DefinitionID: "go-test",
		Required:     true,
		Status:       "fail",
		Stderr:       "--- FAIL: TestX",
	}}
	gateFailBuild := []GateCheckResult{{
		DefinitionID: "go-build",
		Required:     true,
		Status:       "fail",
		Stderr:       "undefined: foo.Bar",
	}}

	cases := []struct {
		name       string
		outcome    string
		reason     string
		gates      []GateCheckResult
		workerMode string
		want       string
	}{
		{"merged_clears_worker_mode", "merged", "", nil, FailureModeUnknown, ""},
		{"no_changes_outcome", "no-changes", "agent made no commits", nil, "", FailureModeNoChanges},
		{"no_evidence_outcome", "no-evidence", "agent exited without a commit or no_changes_rationale.txt", nil, "", FailureModeNoEvidenceProduced},

		{"preserved_merge_conflict", "preserved", "merge conflict", nil, "", FailureModeMergeConflict},
		{"preserved_ff_not_possible", "preserved", "ff-merge not possible", nil, "", FailureModeMergeConflict},
		{"preserved_merge_failed", "preserved", "merge failed", nil, "", FailureModeMergeConflict},

		{"preserved_post_run_build", "preserved", "post-run checks failed", gateFailBuild, "", FailureModeBuildFailure},
		{"preserved_post_run_test", "preserved", "post-run checks failed", gateFailTest, "", FailureModeTestFailure},
		{"preserved_post_run_empty_defaults_to_test", "preserved", "post-run checks failed", nil, "", FailureModeTestFailure},

		{"preserved_agent_execution_failed_keeps_worker", "preserved", "agent execution failed", nil, FailureModeContextOverflow, FailureModeContextOverflow},
		{"preserved_no_merge_keeps_worker", "preserved", "--no-merge specified", nil, FailureModeTimeout, FailureModeTimeout},
		{"preserved_unknown_reason_falls_back_to_unknown", "preserved", "something else", nil, "", FailureModeUnknown},

		{"error_keeps_worker_mode", "error", "agent execution failed", nil, FailureModeAuthError, FailureModeAuthError},
		{"error_unknown_when_worker_empty", "error", "agent execution failed", nil, "", FailureModeUnknown},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := classifyLandingFailureMode(tc.outcome, tc.reason, tc.gates, tc.workerMode)
			if got != tc.want {
				t.Fatalf("classifyLandingFailureMode(%q, %q, %d-gates, %q) = %q, want %q",
					tc.outcome, tc.reason, len(tc.gates), tc.workerMode, got, tc.want)
			}
		})
	}
}

// TestFailureModeApplyLandingToResult verifies that ApplyLandingToResult
// writes the refined failure_mode onto the result, giving callers a single
// unified record. This is the contract callers of result.json depend on.
func TestFailureModeApplyLandingToResult(t *testing.T) {
	// Worker recorded a context overflow; landing then merged the result
	// cleanly (unlikely but possible if the worker bounced mid-run and a
	// retry landed). The landing decision wins: failure_mode clears.
	res := &ExecuteBeadResult{
		BeadID:      "ddx-test",
		BaseRev:     "a",
		ResultRev:   "b",
		ExitCode:    0,
		Outcome:     ExecuteBeadOutcomeTaskSucceeded,
		FailureMode: FailureModeContextOverflow, // carried from a prior attempt
	}
	ApplyLandingToResult(res, &BeadLandingResult{Outcome: "merged"})
	if res.FailureMode != "" {
		t.Fatalf("merged landing should clear FailureMode, got %q", res.FailureMode)
	}

	// Worker succeeded; landing could not merge. FailureMode becomes
	// merge_conflict so measurement can bucket the failure.
	res = &ExecuteBeadResult{
		BeadID:      "ddx-test",
		BaseRev:     "a",
		ResultRev:   "b",
		ExitCode:    0,
		Outcome:     ExecuteBeadOutcomeTaskSucceeded,
		FailureMode: "",
	}
	ApplyLandingToResult(res, &BeadLandingResult{Outcome: "preserved", Reason: "merge conflict"})
	if res.FailureMode != FailureModeMergeConflict {
		t.Fatalf("merge conflict landing should set merge_conflict, got %q", res.FailureMode)
	}

	// Worker succeeded; gate failed with a build diagnostic in stderr.
	res = &ExecuteBeadResult{
		BeadID:    "ddx-test",
		BaseRev:   "a",
		ResultRev: "b",
		ExitCode:  0,
		Outcome:   ExecuteBeadOutcomeTaskSucceeded,
	}
	ApplyLandingToResult(res, &BeadLandingResult{
		Outcome: "preserved",
		Reason:  "post-run checks failed",
		GateResults: []GateCheckResult{{
			DefinitionID: "go-build",
			Required:     true,
			Status:       "fail",
			Stderr:       "undefined: foo.Bar",
		}},
	})
	if res.FailureMode != FailureModeBuildFailure {
		t.Fatalf("build-diagnostic gate failure should set build_failure, got %q", res.FailureMode)
	}

	// No-changes landing outcome always maps to no_changes regardless of

// (agent execution failed, context overflow, etc.). Returns "" when the
// bead merged cleanly.
func classifyLandingFailureMode(landingOutcome, landingReason string, gateResults []GateCheckResult, workerMode string) string {
	switch landingOutcome {
	case "merged":
		return ""
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	case "error":
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	case "preserved":
		switch {
		case landingReason == "merge conflict" || landingReason == "merge failed" || landingReason == "ff-merge not possible":
			return FailureModeMergeConflict
		case landingReason == "post-run checks failed", strings.HasPrefix(landingReason, PreMergeChecksReason):
			return classifyGateFailure(gateResults)
		case landingReason == RatchetPreserveReason:
			return FailureModeRatchetMiss
		case landingReason == AttemptIntegrityPreserveReason:
			return FailureModeAttemptIntegrity
		case landingReason == OperatorCancelReason:
			return ""
		}
		// Other preserved reasons (e.g. "agent execution failed",
		// "--no-merge specified") defer to the worker's classification.
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	}
	if workerMode != "" {
		return workerMode
	}
	return FailureModeUnknown
}

// classifyGateFailure inspects failed gate results to distinguish
// build_failure from test_failure. Gate definitions that fail to compile
// before running (go build, tsc, cargo build) typically surface build
// diagnostics in stderr; test runners surface test failure markers. When
// ambiguous, defaults to test_failure since the post-run checks gate is
// test-oriented by convention.
func classifyGateFailure(gateResults []GateCheckResult) string {
	for _, gr := range gateResults {
		if gr.Status != "fail" {
			continue
		}
		combined := strings.ToLower(gr.Stdout + "\n" + gr.Stderr)
		if containsAny(combined,
			"build failed",
			"compilation failed",
			"compile error",
			"compilation error",
			"cannot find package",
			"undefined:",
			"undefined reference",
			"syntax error") {
			return FailureModeBuildFailure
		}
	}
	return FailureModeTestFailure
}

// Worker-level outcome constants — set by ExecuteBead() on the result.
// The parent orchestrator (LandBeadResult + ApplyLandingToResult) then
// overwrites Outcome and Status with the landing decision.
const (
	ExecuteBeadOutcomeTaskSucceeded  = "task_succeeded"
	ExecuteBeadOutcomeTaskFailed     = "task_failed"
	ExecuteBeadOutcomeTaskNoChanges  = "task_no_changes"
	ExecuteBeadOutcomeTaskNoEvidence = "task_no_evidence"
)

// Status constants — used by the loop and other consumers of ExecuteBeadReport.
// These map to specific close/unclaim behaviors in ExecuteBeadWorker.
const (
	ExecuteBeadStatusStructuralValidationFailed = "structural_validation_failed"
	ExecuteBeadStatusExecutionFailed            = "execution_failed"
	ExecuteBeadStatusPostRunCheckFailed         = "post_run_check_failed"
	ExecuteBeadStatusRatchetFailed              = "ratchet_failed"
	ExecuteBeadStatusLandConflict               = "land_conflict"
	ExecuteBeadStatusLandRetry                  = "land_retry"
	ExecuteBeadStatusLandOperatorAttention      = "land_operator_attention"
	ExecuteBeadStatusPushFailed                 = "push_failed"
	ExecuteBeadStatusPushConflict               = "push_conflict"
	ExecuteBeadStatusPreservedNeedsReview       = "preserved_needs_review"
	ExecuteBeadStatusNoEvidenceProduced         = "no_evidence_produced"
	ExecuteBeadStatusNoChanges                  = "no_changes"
	ExecuteBeadStatusAlreadySatisfied           = "already_satisfied"
	ExecuteBeadStatusSuccess                    = "success"
	ExecuteBeadStatusResourceExhausted          = "resource_exhausted"

	// ExecuteBeadStatusDeclinedNeedsDecomposition is a structured outcome
	// signalling that the executor inspected the bead and concluded it cannot
	// be delivered in a single pass — typically because the scope is
	// epic-sized and must first be broken into sub-beads. It is distinct
	// from no_changes (which means "I tried and there was nothing to change")
	// and from execution_failed (which means the agent or harness errored).
	//
	// The loop treats this status as terminal-for-loop: it parks the bead
	// with a long cooldown and records the recommended sub-beads as a
	// structured `decomposition-recommendation` event. No further attempts
	// happen until an operator clears the cooldown (e.g. via
	// `ddx bead cooldown clear`) or splits the bead.
	ExecuteBeadStatusDeclinedNeedsDecomposition = "declined_needs_decomposition"

	// Post-merge review outcomes. The bead was merged, then reviewed;
	// the review returned a non-APPROVE verdict and the bead was reopened.
	ExecuteBeadStatusReviewRequestChanges = "review_request_changes"
	ExecuteBeadStatusReviewBlock          = "review_block"
	ExecuteBeadStatusReviewMalfunction    = "review_malfunction"

	// ExecuteBeadStatusReviewRequestClarification is set when the reviewer
	// returns REQUEST_CLARIFICATION — it cannot adjudicate one or more
	// needs-judgment AC items without operator input. The bead moves to
	// status=proposed (operator lane) without blocking the drain queue.
	ExecuteBeadStatusReviewRequestClarification = "review_request_clarification"

	// ExecuteBeadStatusLandConflictUnresolvable is set when work
	// attempted 3-way ort auto-resolution and (if configured) a focused
	// conflict-resolve agent run for a preserved iteration, and both failed.
	// The bead is parked under LandConflictCooldown for operator review.
	ExecuteBeadStatusLandConflictUnresolvable = "land_conflict_unresolvable"

	// ExecuteBeadStatusLandConflictOperatorRequired is set when the focused
	// conflict-resolve agent escalated to BLOCKING — the conflict requires
	// operator judgment, not automated retry. The bead moves to status=proposed
	// with a kind:land-conflict-operator-required event.
	ExecuteBeadStatusLandConflictOperatorRequired = "land_conflict_operator_required"

	// ExecuteBeadStatusReviewTerminalBlock is set when a BLOCK review verdict
	// is classified as a terminal operator-required condition —
	// review_spec_gap, review_missing_acceptance, review_too_large at depth
	// cap, or review_unsafe_or_out_of_scope. These classes do not re-enter
	// the automated retry cycle and do not consume the no-progress retry
	// budget; the bead moves to status=proposed until an operator
	// intervenes.
	ExecuteBeadStatusReviewTerminalBlock = "review_terminal_block"

	// ExecuteBeadStatusReviewFixableGap is set when a BLOCK review verdict is
	// classified as a fixable gap — the issues are addressable by a repair
	// attempt at higher MinPower with the reviewer's rationale as context.
	// Exactly one repair cycle is scheduled per result_rev; a second
	// review_fixable_gap on the same result_rev falls through to the regular
	// BLOCK triage path instead.
	ExecuteBeadStatusReviewFixableGap = "review_fixable_gap"

	// ExecuteBeadStatusRepairCycleExhausted is set when the candidate-cycle
	// repair loop reaches its per-attempt repair_max_cycles limit before a
	// reviewer approves the candidate. The latest candidate ref is retained for
	// operator inspection.
	ExecuteBeadStatusRepairCycleExhausted = "repair-cycle-exhausted"
)

// ClassifyExecuteBeadStatus maps a landing outcome to the supervisor-visible
// status contract. This is called by ApplyLandingToResult and by callers who
// build an ExecuteBeadReport from a landing result.
func ClassifyExecuteBeadStatus(outcome string, exitCode int, reason string) string {
	if exitCode != 0 {
		return ExecuteBeadStatusExecutionFailed
	}

	switch outcome {
	case "merged":
		// A merged outcome whose reason carries the push-failure marker
		// means the local target branch advanced but `git push` rejected the
		// new tip (large blob, branch protection, auth, divergence, etc.).
		// Classify these as push_failed so the loop refuses to close the
		// bead and operators are forced to investigate.
		if strings.HasPrefix(reason, PushConflictReasonPrefix) {
			return ExecuteBeadStatusPushConflict
		}
		if strings.HasPrefix(reason, PushFailedReasonPrefix) {
			return ExecuteBeadStatusPushFailed
		}
		return ExecuteBeadStatusSuccess
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return ExecuteBeadStatusNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return ExecuteBeadStatusNoEvidenceProduced
	case "error":
		return ExecuteBeadStatusExecutionFailed
	case "preserved":
		switch {
		case reason == "merge conflict" || reason == "merge failed" || reason == "ff-merge not possible":
			return ExecuteBeadStatusLandConflict
		case reason == "post-run checks failed", strings.HasPrefix(reason, PreMergeChecksReason):
			return ExecuteBeadStatusPostRunCheckFailed
		case reason == RatchetPreserveReason:
			return ExecuteBeadStatusRatchetFailed
		case reason == AttemptIntegrityPreserveReason:
			return ExecuteBeadStatusPreservedNeedsReview
		case reason == OperatorCancelReason:
			return ExecuteBeadStatusPreservedNeedsReview
		}
		if isPreservedNeedsReviewReason(reason) {
			return ExecuteBeadStatusPreservedNeedsReview
		}
		// Preserved iterations may still be success when the caller
		// explicitly requested no merge.
		return ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskSucceeded:
		return ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskFailed:
		return ExecuteBeadStatusExecutionFailed
	default:
		return ExecuteBeadStatusExecutionFailed
	}
}

// IsResourceExhaustedStatus reports whether the status is the stable
// host-resource failure classification.
func IsResourceExhaustedStatus(status string) bool {
	return status == ExecuteBeadStatusResourceExhausted
}

func isPreservedNeedsReviewReason(reason string) bool {
	for _, prefix := range []string{
		"evidence commit failed:",
		"large-deletion gate:",
		"syntax sanity gate:",
		"post-land gate failed:",
	} {
		if strings.HasPrefix(reason, prefix) {
			return true
		}
	}
	return false
}

func ExecuteBeadStatusDetail(status, reason, errMsg string) string {
	switch {
	case reason != "" && errMsg != "" && reason != errMsg:
		return reason + ": " + errMsg
	case reason != "":
		return reason
	case errMsg != "":
		return errMsg
	case status != "":
		return status
	default:
		return "unknown"
	}
}

package agent

import "strings"

// OperatorCancelReason marks a landing preserved because the operator
// cancelled the attempt mid-flight via /api/beads/<id>/cancel. ADR-022
// §Cancel SLA: the worker aborts at the next safe point (between LLM turns /
// git ops) and emits a preserved_for_review result with this exact reason.
const OperatorCancelReason = "operator_cancel"

// PushFailedReasonPrefix is the canonical Reason prefix written by the
// landing layer when `git push` rejects the new tip after a local merge or
// fast-forward succeeded. ClassifyExecuteBeadStatus matches on this prefix
// to map a merged-locally-but-not-pushed outcome to push_failed instead of
// success, so the bead stays open.
const PushFailedReasonPrefix = "landed locally; push failed:"

// PushConflictReasonPrefix marks a more specific failure mode than
// PushFailedReasonPrefix: the local push was rejected because the remote
// advanced, the loop attempted an automatic pull/merge to recover, and the
// merge produced a conflict the loop cannot resolve. The bead is parked for
// human review with a short cooldown rather than a year-long park.
const PushConflictReasonPrefix = "landed locally; push conflict:"

// FailureMode constants classify *why* an execution did not land cleanly.
// They are orthogonal to Outcome/Status: a single failed attempt carries one
// outcome (e.g. preserved) and one failure mode (e.g. merge_conflict) so
// measurement surfaces can aggregate failures by cause.
const (
	FailureModeContextOverflow                = "context_overflow"
	FailureModeMergeConflict                  = "merge_conflict"
	FailureModeTestFailure                    = "test_failure"
	FailureModeBuildFailure                   = "build_failure"
	FailureModeTimeout                        = "timeout"
	FailureModeAuthError                      = "auth_error"
	FailureModeNoChanges                      = "no_changes"
	FailureModeNoEvidenceProduced             = "no_evidence_produced"
	FailureModeRatchetMiss                    = "ratchet_miss"
	FailureModeNoViableProvider               = "no_viable_provider"
	FailureModeProviderConnectivity           = "provider_connectivity"
	FailureModeServerUnavailable              = "server_unavailable"
	FailureModeHarnessNotInstalled            = "harness_not_installed"
	FailureModeBlockedByPassthroughConstraint = "blocked_by_passthrough_constraint"
	FailureModeAgentPowerUnsatisfied          = "agent_power_unsatisfied"
	FailureModeLockContention                 = "lock_contention"
	FailureModeWorktreeLost                   = "worktree_lost"
	// FailureModeRouteResolutionTimeout classifies an attempt that was parked
	// because route resolution / routing preflight exceeded the configured
	// route-resolution timeout. The lease is released and the bead is flagged
	// for operator attention rather than auto-retried (ddx-d8970a7b).
	FailureModeRouteResolutionTimeout = "route_resolution_timeout"
	// FailureModeProgressWatchdog classifies an attempt the progress watchdog
	// terminated because phase-empty heartbeats (harness/model/route all empty)
	// persisted past the phase budget. The worker appeared fresh to the
	// liveness TTL while making no forward progress, so the lease is released
	// and the bead is flagged for operator attention (ddx-dc23f001, parent
	// ddx-8f2e0ebf criterion B).
	FailureModeProgressWatchdog = "progress_watchdog"
	// FailureModeConsecutiveWedge classifies a bead the consecutive-wedge guard
	// stopped re-claiming because it wedged (route_resolution_timeout or
	// progress_watchdog) on consecutive claims up to the threshold. The bead is
	// parked to proposed for operator attention so the single-threaded worker
	// keeps draining the rest of the queue instead of re-wedging the same bead
	// indefinitely (ddx-9714eaac, parent ddx-8f2e0ebf criterion E).
	FailureModeConsecutiveWedge = "consecutive_wedge"
	// FailureModeAttemptIntegrity classifies an attempt that produced commits
	// and a clean agent exit but failed DDx's structured post-agent integrity
	// validation (post-commit mutation, empty pre-commit gate evidence, or
	// uncommitted tracked changes after the implementation commit). It is
	// distinct from implementation/agent failures so operators can tell a DDx
	// validation rejection apart from a genuine task failure (ddx-725b65b4).
	FailureModeAttemptIntegrity = "attempt_integrity"
	// FailureModeLandRetry classifies land/ref/index coordination failures
	// where the implementation result is still valid and the worker should
	// retry/reconcile the landing step instead of escalating implementation.
	FailureModeLandRetry = "land_retry"
	// FailureModeLandOperatorAttention classifies land/ref/index coordination
	// failures where local staged state includes operator-owned work and must
	// be reviewed before DDx lands or retries the result.
	FailureModeLandOperatorAttention = "land_operator_attention"
	FailureModeUnknown               = "unknown"
)

// ResourceExhaustedStopMessage is the operator-visible message emitted when
// execution must stop because the host cannot safely continue draining the
// queue.
const ResourceExhaustedStopMessage = "resource exhausted after cleanup; stopping work loop"

// ClassifyFailureMode derives a failure_mode for a worker-level result from
// its outcome, exit code, and error message. Returns "" when the outcome is
// task_succeeded (success carries no failure mode). task_no_changes always
// maps to FailureModeNoChanges regardless of error text.
//
// For task_failed (or non-zero exit code), the error message is scanned for
// well-known substrings. The order matters: context/auth/timeout patterns
// are checked before generic test/build patterns so a "test timed out"
// classifies as timeout rather than test_failure. Anything unrecognised
// maps to FailureModeUnknown so aggregates never hide a missed pattern.
func ClassifyFailureMode(outcome string, exitCode int, errMsg string) string {
	switch outcome {
	case ExecuteBeadOutcomeTaskSucceeded:
		if exitCode == 0 {
			return ""
		}
		// Degenerate: success outcome with non-zero exit. Treat as unknown
		// failure rather than success so the aggregate flags the anomaly.
	case ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	}

	lower := strings.ToLower(errMsg)
	switch {
	case IsLockContentionError(errMsg):
		return FailureModeLockContention
	case IsWorktreeLostError(errMsg):
		return FailureModeWorktreeLost
	case containsAny(lower,
		"passthrough constraint unsatisfiable",
		"passthrough constraint:",
		"max_power is less than min_power",
		"max_power exceeds min_power",
		"must be less than max_power",
		"no viable routing candidate for pins",
		"harness cannot satisfy power constraint",
		"harness pin incompatible with power bounds",
		"model pin incompatible with power bounds",
		"provider pin incompatible with power bounds"):
		return FailureModeBlockedByPassthroughConstraint
	case containsAny(lower,
		"agent power unsatisfied",
		"no model meets min_power",
		"no model with power >=",
		"minimum power not achievable",
		"min_power constraint cannot be satisfied"):
		return FailureModeAgentPowerUnsatisfied
	case containsAny(lower,
		"executable file not found in $path",
		"executable file not found",
		"no such file or directory") &&
		containsAny(lower, "exec:", "harness", "claude", "agent", "codex", "gemini"):
		return FailureModeHarnessNotInstalled
	case containsAny(lower,
		"no viable harness",
		"no harness configured",
		"failed to initialize routing service",
		"resolveroute:",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint",
		"no viable provider"):
		return FailureModeNoViableProvider
	case isServerTransportFailureText(lower):
		return FailureModeServerUnavailable
	case containsAny(lower,
		"context length",
		"context_length_exceeded",
		"context window",
		"maximum context",
		"prompt is too long",
		"prompt too long",
		"token limit",
		"too many tokens",
		"exceeds the context"):
		return FailureModeContextOverflow
	case containsAny(lower,
		"unauthorized",
		"401 unauthorized",
		"invalid api key",
		"invalid_api_key",
		"authentication failed",
		"authentication_error",
		"no api key",
		"missing api key",
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"rate limit",
		"rate_limit",
		"429"):
		return FailureModeAuthError
	case containsAny(lower,
		"timeout",
		"timed out",
		"context deadline exceeded",
		"deadline exceeded",
		"signal: killed"):
		return FailureModeTimeout
	case containsAny(lower,
		"merge conflict",
		"ff-merge not possible",
		"merge failed",
		"automatic merge failed"):
		return FailureModeMergeConflict
	case containsAny(lower,
		"build failed",
		"compilation failed",
		"compile error",
		"compilation error",
		"cannot find package",
		"undefined:",
		"undefined reference",
		"syntax error"):
		return FailureModeBuildFailure
	case containsAny(lower,
		"test failed",
		"tests failed",
		"--- fail:",
		"assertion failed",
		"test failure"):
		return FailureModeTestFailure
	}
	if outcome == ExecuteBeadOutcomeTaskFailed && errMsg != "" {
		return FailureModeUnknown
	}
	if exitCode != 0 {
		return FailureModeUnknown
	}
	return ""
}

// IsWorktreeLostError reports whether errMsg describes the execute-bead
// infrastructure losing the isolated attempt worktree before DDx could inspect
// its HEAD. This deliberately requires both a HEAD/worktree signal and a
// missing-path signal so generic harness "no such file" errors do not get
// bucketed as infrastructure loss.
func IsWorktreeLostError(errMsg string) bool {
	lower := strings.ToLower(errMsg)
	hasHeadSignal := containsAny(lower,
		"failed to read worktree head",
		"git rev-parse head",
		"worktree path missing")
	hasMissingPathSignal := containsAny(lower,
		"chdir",
		"no such file or directory",
		"cannot access",
		"does not exist")
	return hasHeadSignal && hasMissingPathSignal
}

// containsAny reports whether s contains any of the given substrings. s is
// assumed to already be lower-cased by the caller.
func containsAny(s string, needles ...string) bool {
	for _, n := range needles {
		if n == "" {
			continue
		}
		if strings.Contains(s, n) {
			return true
		}
	}
	return false
}

