		return nil, fmt.Errorf("recording candidate cycle state: %w", err)
	}
	if err := writeArtifactJSON(artifacts.ResultAbs, res); err != nil {
		return nil, fmt.Errorf("writing execute-bead result artifact: %w", err)
	}

