   351	// processResult converts execution output to a Result.
   352	func (r *Runner) processResult(harnessName, model string, harness harnessConfig, execResult *ExecResult, execErr error, elapsed time.Duration, ctx context.Context) *Result {
   353		result := &Result{
   354			Harness:    harnessName,
   355			Model:      model,
   356			DurationMS: int(elapsed.Milliseconds()),
   357		}
   358	
   359		if execResult != nil {
   360			result.Output = execResult.Stdout
   361			result.Stderr = execResult.Stderr
   362			result.ExitCode = execResult.ExitCode
   363		}
   364	
   365		if execResult != nil && execResult.EarlyCancel {
   366			result.Error = fmt.Sprintf("cancelled: auth/rate-limit detected (%s)", execResult.CancelReason)
   367			result.ExitCode = -1
   368		} else if execResult != nil && execResult.WallClockTimeout {
   369			// Wall-clock cap fired regardless of stream activity; distinguish
   370			// this from the resettable idle timer so operators can tell the two
   371			// failure modes apart in result.json and session logs.
   372			reportedElapsed := execResult.WallClockElapsed
   373			if reportedElapsed == 0 {
   374				reportedElapsed = elapsed
   375			}
   376			result.Error = fmt.Sprintf("wall-clock deadline exceeded after %v", reportedElapsed.Round(time.Second))
   377			result.ExitCode = -1
   378		} else if execErr != nil {
   379			if errors.Is(execErr, context.DeadlineExceeded) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
   380				result.Error = fmt.Sprintf("timeout after %v", elapsed.Round(time.Second))
   381				result.ExitCode = -1
   382			} else {
   383				result.Error = execErr.Error()
   384				if result.ExitCode == 0 {
   385					result.ExitCode = -1
   386				}
   387			}
   388		} else if execResult != nil && execResult.ExitCode != 0 {
   389			result.Error = execResult.Stderr
   390		}
