   393		usage := ExtractUsage(harnessName, result.Output)
   394		result.InputTokens = usage.InputTokens
   395		result.CachedTokens = usage.CachedTokens
   396		result.OutputTokens = usage.OutputTokens
   397		result.CostUSD = usage.CostUSD
   398		return result
   399	}
