   401	// UsageData holds structured token usage from a structured agent output.
   402	type UsageData struct {
   403		InputTokens  int
   404		CachedTokens int
   405		OutputTokens int
   406		CostUSD      float64
   407	}
   408	
   409	// ExtractUsage parses structured token usage from agent output.
   410	// For codex, it scans JSONL output for a turn.completed event and reads the usage object.
   411	// For claude, it parses the --output-format json envelope (whole output or last non-empty line).
   412	// Returns zero-value UsageData if parsing fails or the harness is unsupported.
   413	func ExtractUsage(harnessName string, output string) UsageData {
   414		switch harnessName {
   415		case "codex":
   416			for _, line := range strings.Split(output, "\n") {
   417				line = strings.TrimSpace(line)
   418				if line == "" || !strings.Contains(line, `"turn.completed"`) {
   419					continue
   420				}
   421				var event struct {
   422					Type  string `json:"type"`
   423					Usage struct {
   424						InputTokens  int `json:"input_tokens"`
   425						OutputTokens int `json:"output_tokens"`
   426					} `json:"usage"`
   427				}
   428				if err := json.Unmarshal([]byte(line), &event); err != nil {
   429					continue
   430				}
   431				if event.Type == "turn.completed" {
   432					return UsageData{
   433						InputTokens:  event.Usage.InputTokens,
   434						OutputTokens: event.Usage.OutputTokens,
   435					}
   436				}
   437			}
   438			return UsageData{}
   439		case "claude":
   440			// Claude may emit either the legacy single-JSON envelope
   441			// ({"usage":{...},"total_cost_usd":N,"result":"..."}) or a stream-json
   442			// sequence of one JSON event per line, the last of which is a
   443			// {"type":"result",...} event with the same usage/cost fields.
   444			return extractUsageClaude(output)
   445		case "opencode":
   446			// opencode -f json emits a JSON object; parse usage fields if present.
   447			var envelope struct {
   448				Usage struct {
   449					InputTokens  int `json:"input_tokens"`
   450					OutputTokens int `json:"output_tokens"`
   451				} `json:"usage"`
   452				TotalCostUSD float64 `json:"total_cost_usd"`
   453			}
   454			if err := json.Unmarshal([]byte(output), &envelope); err != nil {
   455				// Try last non-empty line (in case of preamble).
   456				lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
   457				last := ""
   458				for i := len(lines) - 1; i >= 0; i-- {
   459					if strings.TrimSpace(lines[i]) != "" {
   460						last = lines[i]
   461						break
   462					}
   463				}
   464				if last == "" {
   465					return UsageData{}
   466				}
   467				if err2 := json.Unmarshal([]byte(last), &envelope); err2 != nil {
   468					return UsageData{}
   469				}
   470			}

