    70	// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
    71	// total) embedded in argv strings or worktree paths.
    72	var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)
    73	
    74	// executionWorktreePattern matches the conventional execute-bead worktree
    75	// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
    76	// in a path. The directory name is enough to identify the worktree even when
    77	// the surrounding path is unconventional.
    78	var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)
    79	
    80	// InferBead extracts a bead ID and execution worktree path from the worker's
    81	// command line and current working directory. It returns the longest worktree
    82	// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
    83	// the inline worker has chdir'd into the isolated worktree), and the first
    84	// bead ID matched in either the command line or the worktree path.
    85	//
    86	// Either return value may be empty when no signal is present, which is the
    87	// expected case for a long-running `ddx work` drain that has not yet started
    88	// a specific bead.
    89	func InferBead(cmdline, cwd string) (beadID, worktree string) {
    90		worktree = extractWorktreePath(cwd)
    91		if worktree == "" {
    92			worktree = extractWorktreePath(cmdline)
    93		}
    94	
    95		if m := beadIDPattern.FindString(worktree); m != "" {
    96			beadID = m
    97		}
    98		if beadID == "" {
    99			if m := beadIDPattern.FindString(cmdline); m != "" {
   100				beadID = m
   101			}
   102		}
   103		if beadID == "" {
   104			if m := beadIDPattern.FindString(cwd); m != "" {
   105				beadID = m
   106			}
   107		}
   108		return beadID, worktree
   109	}
   110	
   111	func extractWorktreePath(s string) string {
   112		if s == "" {
   113			return ""
   114		}
   115		if !strings.Contains(s, ".execute-bead-wt-") {
   116			return ""
   117		}
   118		matches := executionWorktreePattern.FindStringIndex(s)
   119		if matches == nil {
   120			return ""
   121		}
   122		start := matches[0]
   123		end := matches[1]
   124		for start > 0 {
   125			r := s[start-1]
   126			if r == ' ' || r == '\x00' || r == '\t' {
   127				break
   128			}
   129			start--
   130		}
   131		for end < len(s) {
   132			r := s[end]
   133			if r == ' ' || r == '\x00' || r == '\t' {
   134				break
   135			}
   136			end++
   137		}
   138		return s[start:end]
   139	}
