   141	// FilterByProject returns workers whose ProjectRoot resolves to the same path
   142	// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
   143	// filepath.EvalSymlinks so a symlinked checkout matches its real path.
   144	func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
   145		target := canonicalPath(projectRoot)
   146		out := make([]LiveWorker, 0, len(workers))
   147		for _, w := range workers {
   148			if SamePath(w.ProjectRoot, target) {
   149				out = append(out, w)
   150			}
   151		}
   152		return out
   153	}
   154	
   155	// SamePath reports whether a and b refer to the same on-disk location after
   156	// canonicalisation. It tolerates empty inputs (returning false) so callers
   157	// can safely compare optional fields without prefiltering.
   158	func SamePath(a, b string) bool {
   159		ca := canonicalPath(a)
   160		cb := canonicalPath(b)
   161		if ca == "" || cb == "" {
   162			return false
   163		}
   164		return ca == cb
   165	}
   166	
   167	func canonicalPath(p string) string {
   168		if strings.TrimSpace(p) == "" {
   169			return ""
   170		}
   171		abs, err := filepath.Abs(p)
   172		if err != nil {
   173			abs = filepath.Clean(p)
   174		}
   175		if resolved, err := filepath.EvalSymlinks(abs); err == nil {
   176			return resolved
   177		}
   178		return abs
   179	}
