   214	func writeWorkTerminalSummary(w io.Writer, result *agent.ExecuteBeadLoopResult) {
   215		closed, changed, alreadySatisfied, preserved := countWorkTerminalOutcomes(result)
   216		fmt.Fprintf(w, "worker exited: %s\n", workExitSummary(result))
   217		fmt.Fprintf(w, "attempts: %d  |  closed: %d  |  changed: %d  |  already-satisfied: %d  |  preserved: %d  |  failures: %d\n",
