    41	func parseExecuteLoopSpec(cmd *cobra.Command, treatPassthroughAsOpaque bool) (executeloop.ExecuteLoopSpec, executeloop.DispatchOptions, error) {
    42		projectRoot, _ := cmd.Flags().GetString("project")
    43		fromRev, _ := cmd.Flags().GetString("from")
    44		harness, _ := cmd.Flags().GetString("harness")
    45		model, _ := cmd.Flags().GetString("model")
    46		profile, _ := cmd.Flags().GetString("profile")
    47		provider, _ := cmd.Flags().GetString("provider")
    48		effort, _ := cmd.Flags().GetString("effort")
    49		attemptBackend, _ := cmd.Flags().GetString("attempt-backend")
    50		ignoreCooldown, _ := cmd.Flags().GetBool("ignore-cooldown")
    51		cooldownReason, _ := cmd.Flags().GetString("reason")
    52		once, _ := cmd.Flags().GetBool("once")
    53		watch, _ := cmd.Flags().GetBool("watch")
    54		rawIdleInterval, _ := cmd.Flags().GetDuration("idle-interval")
    55		asJSON, _ := cmd.Flags().GetBool("json")
    56		dispatchJSON := ""
    57		if asJSON {
    58			dispatchJSON = "true"
    59		}
    60		local, _ := cmd.Flags().GetBool("local")
    61		noReview, _ := cmd.Flags().GetBool("no-review")
    62		noReviewAck, _ := cmd.Flags().GetBool("no-review-i-know-what-im-doing")
    63		reviewHarness, _ := cmd.Flags().GetString("review-harness")
    64		reviewModel, _ := cmd.Flags().GetString("review-model")
    65		maxCostUSD, _ := cmd.Flags().GetFloat64("max-cost")
    66		maxBeadCostUSD, _ := cmd.Flags().GetFloat64("max-bead-cost")
    67		maxRecoveryCostUSD, _ := cmd.Flags().GetFloat64("max-recovery-cost")
    68		preClaimTimeout, _ := cmd.Flags().GetDuration("preclaim-timeout")
    69		routeResolutionTimeout, _ := cmd.Flags().GetDuration("route-resolution-timeout")
    70		requestTimeout, _ := cmd.Flags().GetDuration("request-timeout")
    71		rateLimitMaxWait, _ := cmd.Flags().GetDuration("rate-limit-max-wait")
    72		minPower, _ := cmd.Flags().GetInt("min-power")
    73		maxPower, _ := cmd.Flags().GetInt("max-power")
    74	
    75		if noReview && !noReviewAck {
    76			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--no-review requires --no-review-i-know-what-im-doing (break-glass acknowledgement)")
    77		}
    78		cooldownReason = strings.TrimSpace(cooldownReason)
    79		if ignoreCooldown && cooldownReason == "" {
    80			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--ignore-cooldown requires --reason \"<text>\"")
    81		}
    82		if once && watch {
    83			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--once and --watch are mutually exclusive")
    84		}
    85		if !watch && cmd.Flags().Changed("idle-interval") {
    86			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--idle-interval only applies in watch mode; pass --watch")
    87		}
    88	
    89		mode := executeloop.ModeDrain
    90		var idleInterval executeloop.Duration
    91		if once {
    92			mode = executeloop.ModeOnce
    93		} else if watch {
    94			mode = executeloop.ModeWatch
    95			idleInterval = executeloop.Duration{Duration: rawIdleInterval}
    96		}
    97	
    98		spec := executeloop.ExecuteLoopSpec{
    99			ProjectRoot:            projectRoot,
   100			Harness:                harness,
   101			Model:                  model,
   102			Profile:                profile,
   103			Provider:               provider,
   104			Effort:                 effort,
   105			AttemptBackend:         attemptBackend,
   106			Mode:                   mode,
   107			IdleInterval:           idleInterval,
   108			NoReview:               noReview,
   109			ReviewHarness:          reviewHarness,
   110			ReviewModel:            reviewModel,
   111			IgnoreCooldown:         ignoreCooldown,
   112			CooldownOverrideReason: cooldownReason,
   113			OpaquePassthrough:      treatPassthroughAsOpaque,
   114			MaxCostUSD:             maxCostUSD,
   115			MaxBeadCostUSD:         maxBeadCostUSD,
   116			MaxRecoveryCostUSD:     maxRecoveryCostUSD,
   117			PreClaimTimeout:        executeloop.Duration{Duration: preClaimTimeout},
   118			RouteResolutionTimeout: executeloop.Duration{Duration: routeResolutionTimeout},
   119			RequestTimeout:         executeloop.Duration{Duration: requestTimeout},
   120			RateLimitMaxWait:       executeloop.Duration{Duration: rateLimitMaxWait},
   121			MinPower:               minPower,
   122			MaxPower:               maxPower,
   123			FromRev:                fromRev,
   124		}
   125		spec.ApplyDefaults()
   126		if err := spec.Validate(); err != nil {
   127			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, err
   128		}
   129	
   130		return spec, executeloop.DispatchOptions{Local: local, JSON: dispatchJSON}, nil
   131	}
