   184	func (f *CommandFactory) runAgentExecuteLoopImpl(cmd *cobra.Command, treatPassthroughAsOpaque bool, tryTargetBeadID string) error {
   185		spec, dispatch, err := parseExecuteLoopSpec(cmd, treatPassthroughAsOpaque)
   186		if err != nil {
   187			return err
   188		}
   189		projectFlag := spec.ProjectRoot
   190		projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
   191		spec.ProjectRoot = projectRoot
   192		beadStoreRoot := f.commandBeadStoreRoot(projectFlag, projectRoot)
   193		if tryTargetBeadID != "" {
   194			spec.Mode = executeloop.ModeOnce
   195			spec.IdleInterval = executeloop.Duration{}
   196		}
   197		spec.Profile = agent.NormalizeRoutingProfile(spec.Profile)
   198	
   199		noRoutingFlags := spec.Harness == "" && spec.Model == "" && spec.Provider == "" &&
   200			spec.Profile == "" && spec.MinPower == 0 &&
   201			spec.MaxPower == 0 && !cmd.Flags().Changed("harness") &&
   202			!cmd.Flags().Changed("model") && !cmd.Flags().Changed("provider") &&
   203			!cmd.Flags().Changed("profile") &&
   204			!cmd.Flags().Changed("min-power") && !cmd.Flags().Changed("max-power")
   205		hasProjectRoutingConfig := projectHasRoutingConfig(projectRoot)
   206		autoInferPowerClass := noRoutingFlags && !hasProjectRoutingConfig
   207	
   208		store := bead.NewStore(beadStoreRoot)
   209		workerStore := agent.ExecuteBeadLoopStore(store)
   210		if spec.IgnoreCooldown {
   211			workerStore = newIgnoreCooldownStore(store)
   212		}
   213		jsonOutput := dispatch.JSON == "true"
   214		cleanupLog := cmd.ErrOrStderr()
   215		if jsonOutput {
   216			cleanupLog = io.Discard
   217		}
   218		cleanupRunner := newStartupHousekeepingRunner(projectRoot)
   219		if tryTargetBeadID == "" && spec.Mode != executeloop.ModeWatch {
   220			if breakdown, bErr := store.ReadyExecutionBreakdown(); bErr != nil {
   221				return bErr
   222			} else if len(breakdown.ExecutionReady) == 0 && len(breakdown.RetryCooldown) == 0 {
   223				if _, cleanupErr := cleanupRunner.Cleanup(cmd.Context()); cleanupErr != nil {
