const (
	// DefaultLoadPressureThreshold is the normalized 5-minute load average per
	// core above which the worker should pause before claiming more work.
	DefaultLoadPressureThreshold = 2.5

	transportFailureWindow    = 10 * time.Minute
	transportFailureThreshold = 3
	transportFailureCooldown  = 5 * time.Minute
	loadPressureBackoffMin    = 30 * time.Second
	loadPressureBackoffMax    = 5 * time.Minute
	loadPressureBackoffScale  = 2 * time.Minute
)

type transportFailureCooldownState struct {
	recent        []time.Time
	cooldownUntil time.Time
}

func (s *transportFailureCooldownState) record(at time.Time) {
	cutoff := at.Add(-transportFailureWindow)
	kept := s.recent[:0]
	for _, ts := range s.recent {
		if !ts.Before(cutoff) {
			kept = append(kept, ts)
		}
	}
	s.recent = append(kept, at)
	if len(s.recent) < transportFailureThreshold {
		return
	}
	until := at.Add(transportFailureCooldown)
	if until.After(s.cooldownUntil) {
		s.cooldownUntil = until
	}
}

func (s *transportFailureCooldownState) delay(now time.Time) time.Duration {
	if s == nil || s.cooldownUntil.IsZero() {
		return 0
	}
	if now.Before(s.cooldownUntil) {
		return s.cooldownUntil.Sub(now)
	}
	return 0
}

func (s *transportFailureCooldownState) recentCount(now time.Time) int {
	if s == nil {
		return 0
	}
	cutoff := now.Add(-transportFailureWindow)
	count := 0
	for _, ts := range s.recent {
		if !ts.Before(cutoff) {
			count++
		}
	}
	return count
}

func applyPreClaimBackoff(ctx context.Context, runtime ExecuteBeadLoopRuntime, state *executeBeadLoopState, emit func(string, map[string]any)) (bool, error) {
	now := state.now().UTC()
	if delay := state.transportFailures.delay(now); delay > 0 {
		count := state.transportFailures.recentCount(now)
		detail := transportFailureCooldownDetail(count, delay)
		emit("loop.transport_failure_cooldown", map[string]any{
			"reason":         "transport_failure_cooldown",
			"recent_failures": count,
			"window":         transportFailureWindow.String(),
			"delay":          delay.String(),
			"detail":         detail,
		})
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "transport failure cooldown: %s\n", detail)
		}
		if err := runtime.backoffSleep(ctx, delay); err != nil {
			return true, err
		}
		return true, nil
	}
	snapshot, err := runtime.loadPressureSnapshot()
	if err != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "load pressure snapshot failed: %v; continuing\n", err)
		}
		return false, nil
	}
	threshold := runtime.effectiveLoadPressureThreshold()
	delay := loadPressureBackoffDelay(snapshot, threshold)
	if delay <= 0 {
		return false, nil
	}
	detail := loadPressureBackoffDetail(snapshot, threshold, delay)
	emit("loop.load_pressure_backoff", map[string]any{
		"reason":      "load_pressure_backoff",
		"normalized":  snapshot.Normalized(),
		"load1":       snapshot.Load1,
		"load5":       snapshot.Load5,
		"load15":      snapshot.Load15,
		"cores":       snapshot.Cores,
		"threshold":   threshold,
		"delay":       delay.String(),
		"detail":      detail,
	})
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "load pressure backoff: %s\n", detail)
	}
	if err := runtime.backoffSleep(ctx, delay); err != nil {
		return true, err
	}
	return true, nil
}

func (runtime ExecuteBeadLoopRuntime) effectiveLoadPressureThreshold() float64 {
	if runtime.LoadPressureThreshold > 0 {
		return runtime.LoadPressureThreshold
	}
	return 0
}

func (runtime ExecuteBeadLoopRuntime) loadPressureSnapshot() (workerstatus.LoadPressure, error) {
	if runtime.LoadPressureSnapshot != nil {
		return runtime.LoadPressureSnapshot()
	}
	return workerstatus.LoadPressureSnapshot()
}

func (runtime ExecuteBeadLoopRuntime) backoffSleep(ctx context.Context, d time.Duration) error {
	if runtime.BackoffSleep != nil {
		return runtime.BackoffSleep(ctx, d, runtime.WakeCh)
	}
	return sleepOrWake(ctx, d, runtime.WakeCh)
}

func loadPressureBackoffDelay(snapshot workerstatus.LoadPressure, threshold float64) time.Duration {
	if !snapshot.OverThreshold(threshold) {
		return 0
	}
	overload := snapshot.Normalized() - threshold
	if overload <= 0 {
		return 0
	}
	delay := time.Duration(overload * float64(loadPressureBackoffScale))
	if delay < loadPressureBackoffMin {
		delay = loadPressureBackoffMin
	}
	if delay > loadPressureBackoffMax {
		delay = loadPressureBackoffMax
	}
	return delay
}

func loadPressureBackoffDetail(snapshot workerstatus.LoadPressure, threshold float64, delay time.Duration) string {
	return fmt.Sprintf(
		"normalized 5m load %.2f over threshold %.2f (load1=%.2f load5=%.2f load15=%.2f cores=%d); backing off %s",
		snapshot.Normalized(),
		threshold,
		snapshot.Load1,
		snapshot.Load5,
		snapshot.Load15,
		snapshot.Cores,
		delay.Round(time.Second),
	)
}

func transportFailureCooldownDetail(count int, delay time.Duration) string {
	return fmt.Sprintf(
		"%d transport exit status 1 outcomes within %s; delaying next claim by %s",
		count,
		transportFailureWindow,
		delay.Round(time.Second),
	)
}

func transportFailureCooldownReason(report ExecuteBeadReport) bool {
	if report.OutcomeReason != "transport" {
		return false
	}
	detail := strings.ToLower(strings.TrimSpace(report.Detail))
	return containsExitStatusOne(detail)
}

func classifyTransportOutcomeDetail(report ExecuteBeadReport, combined string) (string, bool) {
	lower := strings.ToLower(combined)
	switch {
	case strings.Contains(lower, "provider killed by sigkill"):
		return "provider killed by SIGKILL (likely OOM)", true
	case strings.Contains(lower, "provider terminated by sigterm"):
		return "provider terminated by SIGTERM", true
	case strings.Contains(lower, "provider terminated by sigint"):
		return "provider terminated by SIGINT", true
	case containsExitStatusOne(lower):
		return "exit status 1", true
	default:
		return "", false
	}
}

