		// this from the resettable idle timer so operators can tell the two
		// failure modes apart in result.json and session logs.
		reportedElapsed := execResult.WallClockElapsed
		if reportedElapsed == 0 {
			reportedElapsed = elapsed
		}
		result.Error = fmt.Sprintf("wall-clock deadline exceeded after %v", reportedElapsed.Round(time.Second))
		result.ExitCode = -1
	} else if execErr != nil {
		if errors.Is(execErr, context.DeadlineExceeded) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
			result.Error = fmt.Sprintf("timeout after %v", elapsed.Round(time.Second))
			result.ExitCode = -1
		} else {
			result.Error = execErr.Error()
			if result.ExitCode == 0 {
				result.ExitCode = -1
			}
		}
	} else if execResult != nil && execResult.ExitCode != 0 {
		if execResult.SignalName != "" {
			result.Error = describeProviderExitSignal(execResult.SignalName)
		} else {
			stderr := strings.TrimSpace(execResult.Stderr)
			exitText := fmt.Sprintf("exit status %d", execResult.ExitCode)
			switch {
			case stderr == "":
				result.Error = exitText
			case strings.Contains(strings.ToLower(stderr), strings.ToLower(exitText)):
				result.Error = stderr
			default:
				result.Error = stderr + "\n" + exitText
			}
		}
	}

	result.Tokens = ExtractTokens(result.Output, harness)
	usage := ExtractUsage(harnessName, result.Output)
	result.InputTokens = usage.InputTokens
	result.CachedTokens = usage.CachedTokens
	result.OutputTokens = usage.OutputTokens
	result.CostUSD = usage.CostUSD
	return result
}

func describeProviderExitSignal(signalName string) string {
	signalName = strings.TrimSpace(signalName)
	switch strings.ToUpper(signalName) {
	case "SIGKILL":
		return "provider killed by SIGKILL (likely OOM)"
	case "SIGTERM":
		return "provider terminated by SIGTERM"
	case "SIGINT":
		return "provider terminated by SIGINT"
	default:
		if signalName == "" {
			return ""
		}
		return fmt.Sprintf("provider terminated by %s", signalName)
	}
}

