func TestApplyPreClaimBackoff_LoadPressureUsesConfiguredThreshold(t *testing.T) {
	fixedNow := time.Date(2026, 6, 29, 12, 0, 0, 0, time.UTC)
	state := &executeBeadLoopState{
		now: func() time.Time { return fixedNow },
	}

	var (
		sleepCalls int
		gotDelay   time.Duration
		events     []string
	)
	runtime := ExecuteBeadLoopRuntime{
		LoadPressureThreshold: 3.5,
		LoadPressureSnapshot: func() (workerstatus.LoadPressure, error) {
			return workerstatus.LoadPressure{Load5: 12, Cores: 4}, nil
		},
		BackoffSleep: func(_ context.Context, d time.Duration, _ <-chan struct{}) error {
			sleepCalls++
			gotDelay = d
			return nil
		},
	}

	backedOff, err := applyPreClaimBackoff(context.Background(), runtime, state, func(event string, _ map[string]any) {
		events = append(events, event)
	})
	require.NoError(t, err)
	assert.False(t, backedOff, "threshold above normalized load should not back off")
	assert.Zero(t, sleepCalls, "sleep must not run below threshold")
	assert.Empty(t, events, "no event should be emitted below threshold")
	assert.Zero(t, gotDelay, "delay must remain zero below threshold")

	runtime.LoadPressureThreshold = 2.5
	backedOff, err = applyPreClaimBackoff(context.Background(), runtime, state, func(event string, _ map[string]any) {
		events = append(events, event)
	})
	require.NoError(t, err)
	assert.True(t, backedOff, "threshold below normalized load should back off")
	assert.Equal(t, 1, sleepCalls, "sleep must run once above threshold")
	assert.Equal(t, "loop.load_pressure_backoff", events[0], "structured load-pressure event missing")
	assert.Greater(t, gotDelay, time.Duration(0), "backoff delay must be positive")
}

func TestApplyPreClaimBackoff_TransportCooldownUsesRecentHistory(t *testing.T) {
	fixedNow := time.Date(2026, 6, 29, 12, 0, 0, 0, time.UTC)
	state := &executeBeadLoopState{
		now: func() time.Time { return fixedNow },
	}
	state.transportFailures.record(fixedNow.Add(-2 * time.Minute))
	state.transportFailures.record(fixedNow.Add(-1 * time.Minute))
	state.transportFailures.record(fixedNow)

	var (
		sleepCalls int
		gotDelay   time.Duration
		events     []map[string]any
	)
	runtime := ExecuteBeadLoopRuntime{
		LoadPressureSnapshot: func() (workerstatus.LoadPressure, error) {
			return workerstatus.LoadPressure{Load5: 0, Cores: 8}, nil
		},
		BackoffSleep: func(_ context.Context, d time.Duration, _ <-chan struct{}) error {
			sleepCalls++
			gotDelay = d
			return nil
		},
	}

	backedOff, err := applyPreClaimBackoff(context.Background(), runtime, state, func(_ string, data map[string]any) {
		events = append(events, data)
	})
	require.NoError(t, err)
	assert.True(t, backedOff, "three recent transport failures must trigger cooldown")
	assert.Equal(t, 1, sleepCalls, "cooldown must sleep once")
	require.Len(t, events, 1, "structured cooldown event missing")
	assert.Equal(t, "transport_failure_cooldown", events[0]["reason"])
	assert.GreaterOrEqual(t, gotDelay, transportFailureCooldown, "cooldown delay must be at least the configured minimum")
	assert.Contains(t, events[0]["detail"], "transport exit status 1 outcomes")
}

