			if result.ExitCode == 0 {
				t.Fatalf("ExitCode = 0, want non-zero for %s", tc.wantSignal)
			}
		})
	}
}

package workerstatus

import "runtime"

// LoadPressure captures the current host load average and CPU core count.
// Normalized comparisons use the 5-minute load average divided by cores.
type LoadPressure struct {
	Load1  float64
	Load5  float64
	Load15 float64
	Cores  int
}

// Normalized returns the 5-minute load average divided by the CPU count.
// A zero or negative core count fails open with 0.
func (p LoadPressure) Normalized() float64 {
	if p.Cores <= 0 {
		return 0
	}
	return p.Load5 / float64(p.Cores)
}

// OverThreshold reports whether the normalized 5-minute load exceeds threshold.
func (p LoadPressure) OverThreshold(threshold float64) bool {
	if threshold <= 0 {
		return false
	}
	return p.Normalized() > threshold
}

// effectiveCores returns a safe CPU count for hosts that do not report one.
func effectiveCores() int {
	cores := runtime.NumCPU()
	if cores <= 0 {
		return 1
	}
	return cores
}

