//go:build linux

package workerstatus

import (
	"fmt"
	"os"
	"strconv"
	"strings"
)

// LoadPressureSnapshot reads /proc/loadavg and returns the host load state.
func LoadPressureSnapshot() (LoadPressure, error) {
	data, err := os.ReadFile("/proc/loadavg")
	if err != nil {
		return LoadPressure{}, fmt.Errorf("read /proc/loadavg: %w", err)
	}
	fields := strings.Fields(strings.TrimSpace(string(data)))
	if len(fields) < 3 {
		return LoadPressure{}, fmt.Errorf("parse /proc/loadavg: %q", strings.TrimSpace(string(data)))
	}
	load1, err := strconv.ParseFloat(fields[0], 64)
	if err != nil {
		return LoadPressure{}, fmt.Errorf("parse /proc/loadavg load1: %w", err)
	}
	load5, err := strconv.ParseFloat(fields[1], 64)
	if err != nil {
		return LoadPressure{}, fmt.Errorf("parse /proc/loadavg load5: %w", err)
	}
	load15, err := strconv.ParseFloat(fields[2], 64)
	if err != nil {
		return LoadPressure{}, fmt.Errorf("parse /proc/loadavg load15: %w", err)
	}
	return LoadPressure{
		Load1:  load1,
		Load5:  load5,
		Load15: load15,
		Cores:  effectiveCores(),
	}, nil
}

